from collections import Counter
class Solution:
    def findOriginalArray(self, changed):
        n = len(changed)
        if n % 2 != 0:
            return []
        cnt = Counter(changed)
        values = sorted(cnt.keys())
        result = []
        def backtrack():
            v = None
            for cand in values:
                if cnt[cand] > 0:
                    v = cand
                    break
            if v is None:
                return True
            if v == 0:
                if cnt[0] < 2:
                    return False
                cnt[0] -= 2
                result.append(0)
                if backtrack():
                    return True
                cnt[0] += 2
                result.pop()
                return False
            double = v * 2
            if cnt.get(double, 0) <= 0:
                return False
            cnt[v] -= 1
            cnt[double] -= 1
            result.append(v)
            if backtrack():
                return True
            cnt[v] += 1
            cnt[double] += 1
            result.pop()
            return False
        if backtrack():
            return result
        return []

