from collections import Counter
class Solution:
    def findOriginalArray(self, changed):
        n = len(changed)
        if n % 2 != 0:
            return []
        cnt = Counter(changed)
        res = []
        for x in sorted(cnt.keys()):
            if cnt[x] <= 0:
                continue
            if x == 0:
                if cnt[0] % 2 != 0:
                    return []
                res.extend([0] * (cnt[0] // 2))
                cnt[0] = 0
                continue
            need = x * 2
            if cnt.get(need, 0) < cnt[x]:
                return []
            cnt[need] -= cnt[x]
            res.extend([x] * cnt[x])
            cnt[x] = 0
        return res

