var findOriginalArray = function(changed) {
    const n = changed.length;
    if (n % 2 !== 0) return [];
    const cnt = new Map();
    for (const v of changed) cnt.set(v, (cnt.get(v) || 0) + 1);
    const values = Array.from(cnt.keys()).sort((a, b) => a - b);
    const res = [];
    for (const x of values) {
        const c = cnt.get(x);
        if (c <= 0) continue;
        if (x === 0) {
            if (c % 2 !== 0) return [];
            for (let i = 0; i < c / 2; i++) res.push(0);
            cnt.set(0, 0);
            continue;
        }
        const need = x * 2;
        const needCount = cnt.get(need) || 0;
        if (needCount < c) return [];
        cnt.set(need, needCount - c);
        for (let i = 0; i < c; i++) res.push(x);
        cnt.set(x, 0);
    }
    return res;
};
